const cdn1 = fetch('https://cdn-1.example.com/image.jpg'); //  404 Not Found
const cdn2 = fetch('https://cdn-2.example.com/image.jpg'); //  Success in 500ms
const cdn3 = fetch('https://cdn-3.example.com/image.jpg'); //  Success in 800ms

Promise.any([cdn1, cdn2, cdn3])
  .then(response => {
    // cdn1 failed, so it was ignored.
    // cdn2 succeeded first, so it wins!
    console.log('Got the image from a CDN!');
  })
  .catch(error => {
    // This only runs if ALL THREE CDNs went down.
    console.error('All CDNs failed.', error.errors);
  });
